using UnityEngine;
using UnityEngine.UI;

public class PlayerStats : MonoBehaviour
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int baseDamage = 10;

    public void TakeDamage(int amount)
    {
        int finalDamage = Mathf.Max(0, amount);
        currentHealth = Mathf.Clamp(currentHealth - finalDamage, 0, maxHealth);
    }

    public void Heal(int amount)
    {
        int healAmount = Mathf.Max(0, amount);
        currentHealth = Mathf.Clamp(currentHealth + healAmount, 0, maxHealth);
    }

    public void AddCurrency(int amount)
    {
        currency = Mathf.Max(0, currency + amount);
    }

    public bool SpendCurrency(int amount)
    {
        int cost = Mathf.Max(0, amount);
        if (currency < cost)
            return false;

        currency -= cost;
        return true;
    }

    public int CalculateDamage(int weaponBonus, float multiplier)
    {
        int bonus = Mathf.Max(0, weaponBonus);
        float finalValue = (baseDamage + bonus) * Mathf.Max(0f, multiplier);
        return Mathf.Max(1, Mathf.RoundToInt(finalValue));
    }
}

public class ShopItem : MonoBehaviour
{
    public string itemName = "Item";
    public int basePrice = 100;
    public int priceIncreasePerPurchase = 25;
    public int purchaseCount = 0;
    public int damageBonus = 0;
    public int healthBonus = 0;

    public int GetCurrentPrice()
    {
        return Mathf.Max(0, basePrice + (purchaseCount * priceIncreasePerPurchase));
    }

    public void ApplyPurchase(PlayerStats player)
    {
        if (player == null)
            return;

        player.baseDamage += Mathf.Max(0, damageBonus);
        player.maxHealth += Mathf.Max(0, healthBonus);
        player.currentHealth = Mathf.Clamp(player.currentHealth + Mathf.Max(0, healthBonus), 0, player.maxHealth);
        purchaseCount++;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItem[] items;
    public Text currencyText;
    public Text healthText;
    public Text damageText;

    private void Start()
    {
        RefreshUI();
    }

    private void Update()
    {
        RefreshUI();
    }

    public bool BuyItem(int index)
    {
        if (playerStats == null || items == null || index < 0 || index >= items.Length)
            return false;

        ShopItem item = items[index];
        if (item == null)
            return false;

        int price = item.GetCurrentPrice();
        if (!playerStats.SpendCurrency(price))
            return false;

        item.ApplyPurchase(playerStats);
        RefreshUI();
        return true;
    }

    public void RefreshUI()
    {
        if (playerStats == null)
            return;

        if (currencyText != null)
            currencyText.text = "Currency: " + playerStats.currency;

        if (healthText != null)
            healthText.text = "Health: " + playerStats.currentHealth + "/" + playerStats.maxHealth;

        if (damageText != null)
            damageText.text = "Damage: " + playerStats.baseDamage;
    }
}

public class CombatExample : MonoBehaviour
{
    public PlayerStats playerStats;
    public int enemyDefense = 2;
    public float damageMultiplier = 1f;

    public void AttackEnemy()
    {
        if (playerStats == null)
            return;

        int damage = playerStats.CalculateDamage(0, damageMultiplier);
        int finalDamage = Mathf.Max(0, damage - Mathf.Max(0, enemyDefense));
        Debug.Log("Enemy took " + finalDamage + " damage.");
    }
}

public class IAPCurrencyGrant : MonoBehaviour
{
    public PlayerStats playerStats;
    public int currencyReward = 1000;

    public void GrantPurchaseReward()
    {
        if (playerStats != null)
            playerStats.AddCurrency(currencyReward);
    }
